import org.moqui.context.ExecutionContext
import org.moqui.impl.tools.JepToolFactory
import jep.Interpreter
import org.moqui.entity.EntityValue
import org.moqui.entity.EntityCondition

ExecutionContext ec = context.ec
final JepToolFactory tool = ec.getTool("Jep", JepToolFactory.class)
Map<String, Object> pyResults = [:]

try (Interpreter interpreter = tool.getInterpreter()) {
    URL scriptUrl = ec.resource.getLocationReference("component://moqui-genicam/script").getUrl()
    String scriptDir = ""
    if (scriptUrl != null) {
        try {
            scriptDir = new File(scriptUrl.toURI()).getAbsolutePath()
        } catch (Throwable t) {
            scriptDir = scriptUrl.getPath()
            if (scriptDir && scriptDir.startsWith("file:")) scriptDir = scriptDir.substring(5)
            if (scriptDir && scriptDir.startsWith("/") && scriptDir.length() > 2 && scriptDir.charAt(2) == ':') scriptDir = scriptDir.substring(1)
        }
    }
    if (!scriptDir) {
        scriptDir = ec.resource.getLocationReference("component://moqui-genicam/script").getLocation()
        if (scriptDir.startsWith("file:")) {
            scriptDir = scriptDir.substring(scriptDir.startsWith("file:///") ? 8 : (scriptDir.startsWith("file:/") ? 6 : 5))
        }
    }
    scriptDir = scriptDir.replace('\\', '/')
    interpreter.exec("import sys")
    interpreter.exec("if '${scriptDir}' not in sys.path: sys.path.append('${scriptDir}')")

    interpreter.set("cti_path", ctiPath)
    interpreter.set("serial_number", serialNumber)
    interpreter.set("device_id", device.deviceId)
    interpreter.set("ec", ec)

    if ("DrtRead" == request.requestTypeEnumId) {
        List<String> paramNames = requestItemList*.query
        interpreter.set("action", "read")
        interpreter.set("parameter_names", paramNames)
        interpreter.set("parameters_map", null)

        ec.logger.info("Executing JEP GenICam Read request for camera ${serialNumber}")
        interpreter.exec("import genicam_bridge")
        interpreter.exec("result = genicam_bridge.run_action(action, cti_path, serial_number, parameter_names=parameter_names, ec=ec, device_id=device_id)")

        pyResults = (Map<String, Object>) interpreter.getValue("result")

    } else if ("DrtWrite" == request.requestTypeEnumId) {
        Map<String, Object> paramsMap = [:]

        requestItemList.each { EntityValue item ->
            EntityValue parameter = ec.entity.find("moqui.math.Parameter")
                .condition("parameterId", item.parameterId).one()
            if (parameter) {
                Object val = parameter.numericValue != null ? parameter.numericValue : parameter.symbolicValue
                if (val == null) val = parameter.parameterEnumId
                if (val != null) {
                    paramsMap.put(item.query, val)
                }
            }
        }

        interpreter.set("action", "write")
        interpreter.set("parameter_names", null)
        interpreter.set("parameters_map", paramsMap)

        ec.logger.info("Executing JEP GenICam Write request for camera ${serialNumber} with parameters: ${paramsMap}")
        interpreter.exec("import genicam_bridge")
        interpreter.exec("result = genicam_bridge.run_action(action, cti_path, serial_number, parameters_map=parameters_map, ec=ec, device_id=device_id)")

        pyResults = (Map<String, Object>) interpreter.getValue("result")
    } else {
        throw new IllegalArgumentException("Unsupported device request type: ${request.requestTypeEnumId} for GenICam camera.")
    }
} catch (Throwable t) {
    ec.logger.error("GenICam JEP action execution failed", t)
    throw t
}

// sync Python results back to Moqui DB parameters
if (pyResults) {
    pyResults.each { String key, Object val ->
        EntityValue item = requestItemList.find { it.query == key }
        if (item) {
            EntityValue parameter = ec.entity.find("moqui.math.Parameter")
                .condition("parameterId", item.parameterId).useCache(false).one()

            if (parameter) {
                parameter = parameter.cloneValue()
                boolean isNumeric = val instanceof Number
                if (isNumeric) {
                    parameter.numericValue = (BigDecimal) val
                    parameter.symbolicValue = null
                } else {
                    parameter.numericValue = null
                    parameter.symbolicValue = val?.toString()
                }
                parameter.update()

                long nextSeq = ec.entity.find("moqui.math.ParameterLog")
                    .condition("parameterId", parameter.parameterId)
                    .count() + 1

                EntityValue logEntry = ec.entity.makeValue("moqui.math.ParameterLog")
                logEntry.setSequencedIdPrimary()
                logEntry.parameterId = parameter.parameterId
                logEntry.sequenceNum = nextSeq
                logEntry.observedDate = ec.user.nowTimestamp
                if (isNumeric) {
                    logEntry.numericValue = (BigDecimal) val
                } else {
                    logEntry.symbolicValue = val?.toString()
                }
                logEntry.create()

                ec.logger.info("Synchronized Parameter ${parameter.parameterId} (${key}) to value: ${val}")
            }
        }
    }
}

