    interpreter.set("device_id", deviceId)
    interpreter.set("ec", ec)
    interpreter.set("action", "video")
    interpreter.set("parameter_names", null)
    interpreter.set("parameters_map", [num_frames: numFrames, output_dir: outputDir])

    ec.logger.info("Executing JEP GenICam Video Stream request for camera ${serialNumber}")
    interpreter.exec("import genicam_bridge")
    interpreter.exec("result = genicam_bridge.run_action(action, cti_path, serial_number, parameters_map=parameters_map, ec=ec, device_id=device_id)")

    pyResults = (Map<String, Object>) interpreter.getValue("result")
} catch (Throwable t) {
    ec.logger.error("GenICam JEP video stream acquisition failed", t)
    throw t
}

context.acquiredFrames = pyResults?.get("acquired_frames")

import org.moqui.context.ExecutionContext
import org.moqui.impl.tools.JepToolFactory
import jep.Interpreter
import jakarta.servlet.http.HttpServletResponse
import java.io.OutputStream

ExecutionContext ec = context.ec
final JepToolFactory tool = ec.getTool("Jep", JepToolFactory.class)

HttpServletResponse response = (HttpServletResponse) ec.web.response
response.setContentType("multipart/x-mixed-replace; boundary=frame")
response.setHeader("Cache-Control", "no-cache, private, must-revalidate")
response.setHeader("Pragma", "no-cache")
response.setHeader("Connection", "keep-alive")

OutputStream os = response.getOutputStream()

try (Interpreter interpreter = tool.getInterpreter()) {
    URL scriptUrl = ec.resource.getLocationReference("component://moqui-genicam/script").getUrl()
    String scriptDir = ""
    if (scriptUrl != null) {
        try {
            scriptDir = new File(scriptUrl.toURI()).getAbsolutePath()
        } catch (Throwable t) {
            scriptDir = scriptUrl.getPath()
            if (scriptDir && scriptDir.startsWith("file:")) scriptDir = scriptDir.substring(5)
            if (scriptDir && scriptDir.startsWith("/") && scriptDir.length() > 2 && scriptDir.charAt(2) == ':') scriptDir = scriptDir.substring(1)
        }
    }
    if (!scriptDir) {
        scriptDir = ec.resource.getLocationReference("component://moqui-genicam/script").getLocation()
        if (scriptDir.startsWith("file:")) {
            scriptDir = scriptDir.substring(scriptDir.startsWith("file:///") ? 8 : (scriptDir.startsWith("file:/") ? 6 : 5))
        }
    }
    scriptDir = scriptDir.replace('\\', '/')

    interpreter.exec("import sys")
    interpreter.exec("if '${scriptDir}' not in sys.path: sys.path.append('${scriptDir}')")
    interpreter.exec("import genicam_bridge")

    interpreter.set("cti_path", ctiPath)
    interpreter.set("serial_number", serialNumber)
    interpreter.set("device_id", deviceId)
    interpreter.set("ec", ec)

    // stream 100 frames (~7 seconds) as a safety-net limit for testing, or until client disconnects
    int maxFrames = 100
    int frameCount = 0

    while (frameCount < maxFrames) {
        interpreter.exec("result = genicam_bridge.run_action('get_frame', cti_path, serial_number, ec=ec, device_id=device_id)")
        Map pyRes = (Map) interpreter.getValue("result")
        byte[] jpegBytes = (byte[]) pyRes?.get("jpeg_bytes")

        if (jpegBytes) {
            try {
                os.write(("--frame\r\nContent-Type: image/jpeg\r\nContent-Length: " + jpegBytes.length + "\r\n\r\n").getBytes())
                os.write(jpegBytes)
                os.write("\r\n".getBytes())
                os.flush()
            } catch (IOException ioEx) {
                ec.logger.info("Live stream client disconnected for camera ${serialNumber}")
                break
            }
        }
        frameCount++
        Thread.sleep(66) // ~15 FPS
    }
} catch (Throwable t) {
    ec.logger.error("GenICam Live MJPEG stream error", t)
    throw t
}

