import org.moqui.context.ExecutionContext
import org.moqui.impl.tools.JepToolFactory
import jep.Interpreter
import org.moqui.entity.EntityValue
import java.io.File

ExecutionContext ec = context.ec
final JepToolFactory tool = ec.getTool("Jep", JepToolFactory.class)
Map<String, Object> pyResults = [:]

try (Interpreter interpreter = tool.getInterpreter()) {
    URL scriptUrl = ec.resource.getLocationReference("component://moqui-genicam/script").getUrl()
    String scriptDir = ""
    if (scriptUrl != null) {
        try {
            scriptDir = new File(scriptUrl.toURI()).getAbsolutePath()
        } catch (Throwable t) {
            scriptDir = scriptUrl.getPath()
            if (scriptDir && scriptDir.startsWith("file:")) scriptDir = scriptDir.substring(5)
            if (scriptDir && scriptDir.startsWith("/") && scriptDir.length() > 2 && scriptDir.charAt(2) == ':') scriptDir = scriptDir.substring(1)
        }
    }
    if (!scriptDir) {
        scriptDir = ec.resource.getLocationReference("component://moqui-genicam/script").getLocation()
        if (scriptDir.startsWith("file:")) {
            scriptDir = scriptDir.substring(scriptDir.startsWith("file:///") ? 8 : (scriptDir.startsWith("file:/") ? 6 : 5))
        }
    }
    scriptDir = scriptDir.replace('\\', '/')
    interpreter.exec("import sys")
    interpreter.exec("if '${scriptDir}' not in sys.path: sys.path.append('${scriptDir}')")

    interpreter.set("cti_path", ctiPath)
    interpreter.set("serial_number", serialNumber)
    interpreter.set("device_id", deviceId)
    interpreter.set("output_dir", outputDir)
    interpreter.set("ec", ec)
    interpreter.set("action", "acquire_3d_frame")

    ec.logger.info("Executing JEP GenICam acquire_3d_frame for camera ${serialNumber}")
    interpreter.exec("import genicam_bridge")
    interpreter.exec("result = genicam_bridge.run_action(action, cti_path, serial_number, ec=ec, device_id=device_id)")

    pyResults = (Map<String, Object>) interpreter.getValue("result")
} catch (Throwable t) {
    ec.logger.error("GenICam JEP 3D frame acquisition failed", t)
    throw t
}

if (pyResults) {
    context.tensorId = pyResults.get("tensorId")
    context.tensorContentId = pyResults.get("tensorContentId")
    context.contentLocation = pyResults.get("contentLocation")
}

iterate.script:
if (content.contentLocation) {
    java.io.File file = new java.io.File(content.contentLocation)
    if (file.exists()) {
        try {
            file.delete()
            ec.logger.info("Deleted old tensor file: ${content.contentLocation}")
        } catch (Exception e) {
            ec.logger.error("Failed to delete tensor file ${content.contentLocation}: ${e.getMessage()}")
        }
    }
}

boolean beganTx = ec.transaction.begin(null)
try {
    ec.entity.find("moqui.math.TensorContent").condition("tensorContentId", content.tensorContentId).deleteAll()
    ec.entity.find("moqui.math.TensorAxis").condition("tensorId", content.tensorId).deleteAll()
    ec.entity.find("moqui.math.Tensor").condition("tensorId", content.tensorId).deleteAll()
    ec.transaction.commit(beganTx)
    deletedCount++
} catch (Throwable t) {
    ec.transaction.rollback(beganTx, "Failed to clean tensor DB records", t)
    ec.logger.error("Failed to delete DB records for tensor ${content.tensorId}: ${t.getMessage()}")
}
